// Nordique Pro — the brand's required PDF-export font (never Quicksand or any
// other substitute). Embedded directly as base64 data URIs rather than linked
// from a font host, since Nordique Pro is a licensed commercial font with no
// public CDN/Google Fonts distribution — the print window has no other way to
// get it. Three weights only (no Regular): Light stands in for body copy,
// Semibold for the brand/section-heading weight, Bold for headings/totals.
//
// Subsetted to Latin + common punctuation and encoded as WOFF2 (via pyftsubset)
// instead of shipping the original full TTFs — cut the embedded payload from
// ~180KB to ~44KB, which matters a lot here: this whole block gets inlined
// into the print window's HTML on every single PDF export, and a bloated
// print document was making the browser's own "Save as PDF" step take a
// very long time to actually produce the file.
const NORDIQUE_LIGHT_B64 = "";
const NORDIQUE_SEMIBOLD_B64 = "";
const NORDIQUE_BOLD_B64 = "";

export const NORDIQUE_FONT_FACE_CSS = `
  @font-face { font-family: 'Nordique Pro'; src: url('data:font/woff2;base64,${NORDIQUE_LIGHT_B64}') format('woff2'); font-weight: 300; font-style: normal; font-display: block; }
  @font-face { font-family: 'Nordique Pro'; src: url('data:font/woff2;base64,${NORDIQUE_SEMIBOLD_B64}') format('woff2'); font-weight: 600; font-style: normal; font-display: block; }
  @font-face { font-family: 'Nordique Pro'; src: url('data:font/woff2;base64,${NORDIQUE_BOLD_B64}') format('woff2'); font-weight: 700; font-style: normal; font-display: block; }
`;
